// Retrieve last successful run timestamp from workflow static data
const workflowStaticData = $getWorkflowStaticData('global');
const lastRun = workflowStaticData.lastSuccessfulRun || '1970-01-01T00:00:00.000Z';

// Capture execution start time to prevent timestamp drift / lost rows
const currentRunStart = new Date().toISOString();

return [{ json: { lastRun, currentRunStart, isFirstRun: lastRun === '1970-01-01T00:00:00.000Z' } }];

// Collects all rows from the Postgres node into a single item.
// Timestamps are pulled from Get Last Run Timestamp via a guarded cross-node reference.
// IMPORTANT: continueOnFail must remain OFF on the Postgres node above.
// If Postgres errors, execution stops here and the watermark is never touched — correct behavior.
// If continueOnFail were ever enabled on Postgres, a failed query would pass an empty
// array through and could incorrectly advance the watermark. Do not enable it.

let lastRunData;
try {
    lastRunData = $('Fetch Last Run Timestamp').first().json;
} catch(e) {
    throw new Error('Get Last Run Timestamp output is unavailable. Do not rename or disable that node. Original error: ' + e.message);
}

const rows = $input.all().map(item => item.json);

return [{ json: {
    rows,
    rowCount: rows.length,
    lastRun: lastRunData.lastRun,
    currentRunStart: lastRunData.currentRunStart,
    isFirstRun: lastRunData.isFirstRun
} }];

const workflowStaticData = $getWorkflowStaticData('global');
const newTimestamp = $('Fetch Last Run Timestamp').first().json.currentRunStart;
workflowStaticData.lastSuccessfulRun = newTimestamp;

// Output matches the shape expected by Send Sync Summary
return [{ json: {
    lastRunUpdated: newTimestamp,
    watermarkAdvanced: true,
    syncComplete: true,
    totalSuccess: 0,
    totalFailures: 0
} }];

const rows = $('Aggregate Postgres Results').first().json.rows || [];
const sharepointSiteId = $('Set Configuration Parameters').first().json.sharepointSiteId;
const sharepointListId = $('Set Configuration Parameters').first().json.sharepointListId;

// FIX #11: Enforce the hard Graph API limit of 20 requests per $batch call
const batchSize = Math.min($('Set Configuration Parameters').first().json.batchSize || 20, 20);

const batches = [];
for (let i = 0; i < rows.length; i += batchSize) {
  const chunk = rows.slice(i, i + batchSize);
  const requests = chunk.map((row, j) => ({
    id: String(row.id || i + j + 1),
    method: 'POST',
    url: `/sites/${sharepointSiteId}/lists/${sharepointListId}/items`,
    headers: { 'Content-Type': 'application/json' },
    // FIX #4: TODO — map your actual Postgres column names to SharePoint field internal names.
    // Example: if your table has columns (id, customer_name, amount), update fields like:
    //   Title: String(row.customer_name || ''),
    //   Amount: row.amount,
    body: {
      fields: {
        Title: String(row.id || row.name || ''),
        ExternalId: String(row.id || ''),
        SyncedAt: new Date().toISOString()
      }
    }
    // FIX #6: dependsOn is intentionally omitted for pure POST creates.
    // If you extend this to upsert (check-then-write), add:
    //   dependsOn: [String(checkRequestId)]
    // to chain the existence-check request before the write.
  }));
  batches.push({ requests, batchIndex: batches.length, totalBatches: Math.ceil(rows.length / batchSize) });
}

return batches.map(b => ({ json: b }));

const batchResponse = $input.item.json || {};

if (!batchResponse.responses) {
  return [{
    json: {
      successCount: 0,
      failCount: 1,
      throttledCount: 0,
      failedIds: ['ENTIRE_BATCH_FAILED'],
      throttledIds: [],
      errorDetails: batchResponse.error ? batchResponse.error.message : 'Unknown Network or API Outage',
      batchProcessed: false
    }
  }];
}

const responses = batchResponse.responses;
const succeeded = responses.filter(r => r.status >= 200 && r.status < 300);
const throttled = responses.filter(r => r.status === 429);
const failed = responses.filter(r => r.status < 200 || (r.status >= 300 && r.status !== 429));

// FIX #7: Extract Retry-After header from throttled responses for visibility.
// Note: n8n's httpRequest does not expose per-sub-request headers from $batch responses.
// Throttled IDs are surfaced in the alert so operators know which rows to manually retry.
// For automated backoff, consider routing throttledIds to a separate queue or
// re-triggering with a Wait node using the max Retry-After value.
const retryAfterValues = throttled
  .map(r => r.headers && r.headers['retry-after'] ? parseInt(r.headers['retry-after'], 10) : null)
  .filter(v => v !== null);
const maxRetryAfter = retryAfterValues.length > 0 ? Math.max(...retryAfterValues) : null;

return [{
  json: {
    successCount: succeeded.length,
    failCount: failed.length,
    throttledCount: throttled.length,
    failedIds: failed.map(r => r.id),
    throttledIds: throttled.map(r => r.id),
    maxRetryAfterSeconds: maxRetryAfter,
    batchProcessed: true
  }
}];

// FIX #5: Use the documented .all() accessor instead of the fragile runIndex/$items() loop.
// $('Verify Batch API Response').all() correctly returns outputs across all SplitInBatches iterations.
const allItems = $('Verify Batch API Response').all();

let totalSuccess = 0;
let allFailures = [];

for (const item of allItems) {
    const res = item.json;
    if (res.successCount) totalSuccess += res.successCount;
    if (res.failedIds && res.failedIds.length > 0) allFailures.push(...res.failedIds);
    if (res.throttledIds && res.throttledIds.length > 0) allFailures.push(...res.throttledIds);
}

const actualFailures = allFailures.filter(id => id !== 'ENTIRE_BATCH_FAILED');
const finalFailures = actualFailures.length > 0 ? actualFailures : allFailures;

return [{
    json: {
        totalSuccess,
        totalFailures: finalFailures.length,
        failedIds: finalFailures
    }
}];

const staticData = $getWorkflowStaticData('global');
const failedIds = $input.item.json.failedIds || [];

// Initialize rolling memory of failed IDs
staticData.knownFailures = staticData.knownFailures || [];

// Find NEW failures not yet alerted on
const newFailures = failedIds.filter(id => !staticData.knownFailures.includes(id));

let shouldAlert = false;

if (newFailures.length > 0) {
    shouldAlert = true;
    const updatedFailures = [...staticData.knownFailures, ...newFailures];
    // Cap at 200 to prevent unbounded memory growth
    // FIX #10: Consider adding { id, ts } TTL objects if stale failure re-alerting is needed.
    staticData.knownFailures = updatedFailures.slice(-200);
}

return [{
    json: {
        ...$input.item.json,
        shouldAlert,
        newFailures
    }
}];

