const staticData = $getWorkflowStaticData('global');

// FIX #4: Guard the cross-node reference so a rename or refactor surfaces immediately.
// Process Loop Results always executes before any path reaching this node.
let loopResults;
try {
    loopResults = $('Process Looped Results').first().json;
} catch(e) {
    // Fallback if Process Loop Results is unavailable due to an unexpected graph error.
    // Should not occur in normal operation — the no-rows path bypasses this node entirely.
    loopResults = $input.item.json;
}

const totalFailures = loopResults.totalFailures ?? 0;

// FIX #3 (CRITICAL): Only advance the watermark if there were zero failures.
// If rows failed, the watermark stays behind so they are re-queried next run.
// NOTE: If the same rows fail persistently (e.g. bad field value causing 400),
// they will be re-queried forever. knownFailures suppresses repeat alerts after
// the first run. To break the cycle, add those IDs to a dead-letter table in
// Postgres and exclude them from the query with: AND id NOT IN (SELECT id FROM sync_dead_letter)
let newTimestamp;
let watermarkAdvanced;

if (totalFailures === 0) {
    newTimestamp = $('Fetch Last Run Timestamp').first().json.currentRunStart;
    staticData.lastSuccessfulRun = newTimestamp;
    watermarkAdvanced = true;
} else {
    newTimestamp = staticData.lastSuccessfulRun || $('Fetch Last Run Timestamp').first().json.lastRun;
    watermarkAdvanced = false;
}

return [{
    json: {
        lastRunUpdated: newTimestamp,
        watermarkAdvanced,
        syncComplete: true,
        totalSuccess: loopResults.totalSuccess ?? 0,
        totalFailures
    }
}];

